    gastronomia: `<svg viewBox="0 0 600 320" aria-hidden="true"><rect width="600" height="320" fill="#7e2131"/><circle cx="300" cy="177" r="118" fill="#fff2dc"/><circle cx="300" cy="177" r="78" fill="#efb445"/><g fill="#d94c36"><circle cx="274" cy="151" r="18"/><circle cx="336" cy="171" r="18"/><circle cx="292" cy="207" r="18"/></g><g stroke="#fff2dc" stroke-width="15"><path d="M112 57v206M86 57v77c0 28 52 28 52 0V57M488 57v206M456 57c0 68 64 68 64 0"/></g></svg>`,
    ferias: `<svg viewBox="0 0 600 320" aria-hidden="true"><rect width="600" height="320" fill="#4e357c"/><path d="M68 102h464l-38-65H106Z" fill="#f7c841"/><path d="M68 102h464v40H68Z" fill="#ec4b72"/><path d="M90 142h420v128H90Z" fill="#f8efe1"/><g fill="#0e8e8b"><rect x="120" y="177" width="83" height="61"/><rect x="258" y="177" width="83" height="61"/><rect x="396" y="177" width="83" height="61"/></g><path d="M55 270h490v27H55Z" fill="#ef9a32"/><g fill="#fff"><circle cx="160" cy="208" r="17"/><circle cx="300" cy="208" r="17"/><circle cx="438" cy="208" r="17"/></g></svg>`,
