function createMedia(event) {
  const media = element("div", "card-media");
  media.dataset.category = categoryId(event);
  const imageUrl = safeHttpUrl(event.image?.url);
  if (imageUrl) {
    const image = document.createElement("img");
    image.src = imageUrl;
    image.alt = event.image?.alt || `Imagen de ${event.title}`;
    image.loading = "lazy";
    image.decoding = "async";
    media.append(image);
    return media;
  }
  media.append(createCategoryArtwork(event));
  return media;
}

function latestAlert(eventId) {
  return state.alerts.find((alert) => alert.event_id === eventId) || null;
}

function eventAlerts(eventId) {
  return state.alerts.filter((alert) => alert.event_id === eventId);
}

function statusLabel(event, alert) {
  if (alert) return publicChangeLabel(alert.change_type);
  if (event.public_status?.cancelled === true) return "Cancelado";
  if (event.public_status?.sold_out === true) return "Agotado";
  if (event.public_status?.registration_open === true) return "Inscripciones abiertas";
  return null;
}

function createCard(event, { featured = false } = {}) {
  const card = element("article", `event-card${featured ? " featured" : ""}`);
  card.dataset.eventId = event.id;
  const alert = latestAlert(event.id);
  const body = element("div", "card-body");
  const top = element("div", "card-topline");
  top.append(element("span", "pill", eventTypeLabel(event.event_type)), element("span", "pill pill-category", primaryCategory(event)));
  const date = element("p", "card-date", scheduleLabel(event.schedule) || "Horario por confirmar");
  const title = element("h3", "", event.title);
  const place = element("p", "card-place");
  const venue = element("strong", "", event.location?.venue || "Lugar por confirmar");
  place.append(venue, document.createTextNode(event.location?.city ? ` · ${event.location.city}` : ""));
  const badges = element("div", "card-badges");
  const status = statusLabel(event, alert);
  if (status) {
    const badge = element("button", "change-badge", status);
    badge.type = "button";
    badge.addEventListener("click", () => openDetail(event, badge, alert?.id));
    badges.append(badge);
  }
  if (event.links?.registration && event.public_status?.registration_closed !== true) {
    badges.append(element("span", "pill", "Con inscripción"));
  }
  const actions = element("div", "card-actions");
  const price = element("span", `price ${event.price?.is_free ? "free" : "paid"}`, priceLabel(event.price));
  actions.append(price);
  const button = element("button", "detail-button", "Ver detalles");
  button.type = "button";
  button.setAttribute("aria-label", `Ver detalles de ${event.title}`);
  button.addEventListener("click", () => openDetail(event, button));
  actions.append(button);
  body.append(top, date, title, place);
  if (badges.childElementCount) body.append(badges);
  body.append(actions, element("div", "card-mosaic"));
  card.append(createMedia(event), body);
  return card;
}

function isWorkshop(event) {
  return ["course", "workshop", "flexible_offer"].includes(event.event_type)
    || event.categories?.some((category) => /taller|curso|formacion/.test(category.id));
}

function upcomingEvents() {
  return eventsForSection(state.dataset.events, "proximos", new Date());
}

function featuredEvents() {
  const candidates = upcomingEvents();
  const preferred = ["musica", "teatro", "exposiciones", "cursos-talleres"];
  const selected = [];
  for (const category of preferred) {
    const match = candidates.find((event) => categoryId(event) === category && !selected.some((item) => item.id === event.id));
    if (match) selected.push(match);
  }
  for (const event of selectFeatured(candidates, state.alerts, 8)) {
    if (selected.length >= 4) break;
    if (!selected.some((item) => item.id === event.id)) selected.push(event);
  }
  return selected.slice(0, 4);
}

function sectionEvents(sectionId) {
  if (sectionId === "destacados") return featuredEvents();
  if (sectionId === "talleres-cursos") return state.dataset.events.filter(isWorkshop);
  return eventsForSection(state.dataset.events, sectionId, new Date());
}

function currentFilters() {
  return {
    ...defaultFilterState(),
    query: dom.query.value.trim(),
    city: dom.city.value,
    categories: dom.category.value ? [dom.category.value] : [],
    price: dom.free.checked ? "gratis" : "todos",
    period: dom.period.value,
  };
}

function filteredSectionEvents() {
  const filters = currentFilters();
  let events = filterEvents(sectionEvents(state.section), filters, new Date());
  if (dom.workshops.checked) events = events.filter(isWorkshop);
  return events;
}

function renderFeatured() {
  dom.featured.replaceChildren(...featuredEvents().map((event) => createCard(event, { featured: true })));
}

function renderCategoryShortcuts() {
  if (!dom.categoryShortcuts) return;
  const counts = new Map();
  for (const event of state.dataset.events) {
    for (const category of event.categories || []) {
      const current = counts.get(category.id) || { ...category, count: 0 };
      current.count += 1;
      counts.set(category.id, current);
    }
  }
  const ordered = [...counts.values()]
    .sort((a, b) => {
      const ai = CATEGORY_PRIORITY.indexOf(a.id);
      const bi = CATEGORY_PRIORITY.indexOf(b.id);
      if (ai !== -1 || bi !== -1) return (ai === -1 ? 999 : ai) - (bi === -1 ? 999 : bi);
      return b.count - a.count || a.label.localeCompare(b.label, "es-CL");
    })
    .slice(0, 10);
  dom.categoryShortcuts.replaceChildren();
  for (const category of ordered) {
    const button = element("button", "category-shortcut");
    button.type = "button";
    button.dataset.categoryId = category.id;
    button.append(
      element("span", "category-symbol", CATEGORY_SYMBOLS[category.id] || "◆"),
      element("strong", "", category.label),
      element("small", "", `${category.count} ${category.count === 1 ? "actividad" : "actividades"}`),
    );
    button.addEventListener("click", () => {
      state.section = "proximos";
      dom.category.value = category.id;
      renderTabs();
      renderResults();
      document.querySelector("#explorar")?.scrollIntoView({ block: "start" });
    });
    dom.categoryShortcuts.append(button);
  }
}

function renderTabs() {
  dom.tabs.replaceChildren();
  dom.topSections.forEach((button) => {
    button.setAttribute("aria-pressed", String(button.dataset.topSection === state.section));
  });
  for (const section of SECTIONS) {
    const button = element("button", "section-tab");
    button.type = "button";
    button.dataset.section = section.id;
    button.setAttribute("aria-pressed", String(state.section === section.id));
    button.append(document.createTextNode(section.label), element("small", "", sectionEvents(section.id).length));
    button.addEventListener("click", () => {
      state.section = section.id;
      renderTabs();
      renderResults();
      document.querySelector("#explorar")?.scrollIntoView({ block: "start" });
    });
    dom.tabs.append(button);
  }
}

function syncCityShortcuts() {
  dom.shortcuts.forEach((button) => button.setAttribute("aria-pressed", String(button.dataset.cityShortcut === dom.city.value)));
  if (dom.topCity) dom.topCity.value = dom.city.value;
  if (dom.topCategory) dom.topCategory.value = dom.category.value;
  if (dom.headerQuery && dom.headerQuery.value !== dom.query.value) dom.headerQuery.value = dom.query.value;
  if (dom.mobileQuery && dom.mobileQuery.value !== dom.query.value) dom.mobileQuery.value = dom.query.value;
}

function updateUrl() {
  const url = new URL(location.href);
  const filters = currentFilters();
  for (const name of ["q", "ciudad", "categoria", "periodo", "gratis", "talleres", "seccion"]) url.searchParams.delete(name);
  if (filters.query) url.searchParams.set("q", filters.query);
  if (filters.city) url.searchParams.set("ciudad", filters.city);
  if (filters.categories[0]) url.searchParams.set("categoria", filters.categories[0]);
  if (filters.period !== "todos") url.searchParams.set("periodo", filters.period);
  if (dom.free.checked) url.searchParams.set("gratis", "true");
  if (dom.workshops.checked) url.searchParams.set("talleres", "true");
  if (state.section !== "proximos") url.searchParams.set("seccion", state.section);
  history.replaceState({}, "", url);
}

function renderResults({ writeUrl = true } = {}) {
  const events = filteredSectionEvents();
  dom.grid.replaceChildren(...events.map((event) => createCard(event)));
  dom.empty.hidden = events.length > 0;
  const section = SECTIONS.find(({ id }) => id === state.section)?.label || "Actividades";
  dom.result.textContent = `${events.length} ${events.length === 1 ? "actividad" : "actividades"} en ${section.toLocaleLowerCase("es-CL")}.`;
  syncCityShortcuts();
  if (writeUrl) updateUrl();
}

function restoreUrlState() {
  const params = new URLSearchParams(location.search);
  dom.query.value = params.get("q") || "";
  dom.city.value = params.get("ciudad") || "";
  dom.category.value = params.get("categoria") || "";
  dom.period.value = ["hoy", "manana", "fin-de-semana"].includes(params.get("periodo")) ? params.get("periodo") : "todos";
  dom.free.checked = params.get("gratis") === "true";
  dom.workshops.checked = params.get("talleres") === "true";
  const requestedSection = params.get("seccion");
  if (SECTIONS.some(({ id }) => id === requestedSection)) state.section = requestedSection;
}

function appendOption(select, id, label) {
  if (!select) return;
  const option = element("option", "", label);
  option.value = id;
  select.append(option);
}

function populateFilters() {
  for (const { id, label } of collectCities(state.dataset.events)) {
    appendOption(dom.city, id, label);
    appendOption(dom.topCity, id, label);
  }
  for (const { id, label } of collectCategories(state.dataset.events)) {
    appendOption(dom.category, id, label);
    appendOption(dom.topCategory, id, label);
  }
}

function definitionList(entries, className = "detail-facts") {
  const list = element("dl", className);
  for (const [label, value] of entries) {
    if (value === undefined || value === null || value === "") continue;
    list.append(element("dt", "", label), element("dd", "", value));
  }
  return list;
}

function appendExternalLink(container, label, value) {
  const url = safeHttpUrl(value);
  if (!url) return;
  const link = element("a", "", label);
  link.href = url;
  link.target = "_blank";
  link.rel = "noopener noreferrer";
  container.append(link);
}

function renderChange(alert) {
  const panel = element("section", "change-panel");
  panel.id = `aviso-${alert.id}`;
  panel.append(element("h3", "", publicChangeLabel(alert.change_type)), element("p", "", alert.message));
  panel.append(definitionList([
    ["Valor anterior", alert.old_value ?? "No aplica"],
    ["Valor nuevo", alert.new_value ?? "No aplica"],
    ["Verificado", formatContractDate(alert.detected_at)],
  ], "change-facts"));
  const official = safeHttpUrl(alert.official_source?.url);
  if (official) {
    const link = element("a", "", `Fuente oficial: ${alert.official_source.name}`);
    link.href = official;
    link.target = "_blank";
    link.rel = "noopener noreferrer";
    panel.append(link);
  }
  return panel;
}

function openDetail(event, trigger, alertId) {
  state.trigger = trigger;
  dom.detailMedia.replaceChildren(createMedia(event));
  dom.detail.replaceChildren();
  const eyebrow = element("p", "eyebrow", `${eventTypeLabel(event.event_type)} · ${primaryCategory(event)}`);
  const title = element("h2", "", event.title);
  title.id = "detail-title";
  const facts = definitionList([
    ["Fecha y horario", scheduleLabel(event.schedule) || "Por confirmar"],
    ["Recinto", event.location?.venue || "Por confirmar"],
    ["Dirección", event.location?.address],
    ["Ciudad", event.location?.city],
    ["Entrada", priceLabel(event.price)],
    ["Organiza", event.organizer],
  ]);
  const description = element("p", "detail-lead", event.description || "Descripción no disponible.");
  const labels = publicStatusLabels(event, state.dataset.publication_date);
  const status = labels.length ? element("p", "pill", `Información actualizada: ${labels.join(" · ")}`) : null;
  const actions = element("div", "detail-actions");
  appendExternalLink(actions, "Sitio oficial", event.links?.official || event.links?.source);
  appendExternalLink(actions, "Inscripción", event.links?.registration);
  appendExternalLink(actions, "Entradas", event.links?.tickets);
  const share = element("button", "", "Compartir");
  share.type = "button";
  share.addEventListener("click", () => shareEvent(event));
  actions.append(share);
  dom.detail.append(eyebrow, title, facts, description);
  if (status) dom.detail.append(status);
  for (const alert of eventAlerts(event.id)) dom.detail.append(renderChange(alert));
  dom.detail.append(actions);
  dom.shareStatus.textContent = "";
  const url = new URL(location.href);
  url.searchParams.set("evento", event.id);
  history.replaceState({}, "", url);
  dom.dialog.showModal();
  if (alertId) document.querySelector(`#aviso-${CSS.escape(alertId)}`)?.scrollIntoView({ block: "center" });
}

async function shareEvent(event) {
  const url = new URL(location.href);
  url.searchParams.set("evento", event.id);
  try {
    if (navigator.share) await navigator.share({ title: event.title, url: url.href });
    else await navigator.clipboard.writeText(url.href);
    dom.shareStatus.textContent = navigator.share ? "Enlace compartido." : "Enlace copiado.";
  } catch (error) {
    if (error?.name !== "AbortError") dom.shareStatus.textContent = "No fue posible compartir el enlace.";
  }
}

function closeDetail() {
  if (dom.dialog.open) dom.dialog.close();
}

function afterDetailClose() {
  const url = new URL(location.href);
  url.searchParams.delete("evento");
  history.replaceState({}, "", url);
  state.trigger?.focus();
}

function clearFilters() {
  dom.form.reset();
  dom.city.value = "";
  dom.category.value = "";
  dom.period.value = "todos";
  renderResults();
  dom.query.focus();
}

async function initialize() {
  try {
    const [dataset, changes] = await Promise.all([
      fetchDataset(fetch, DATASET_PATH),
      fetchChangesDataset(fetch, CHANGES_PATH).catch(() => ({ alerts: [] })),
    ]);
    state.dataset = dataset;
    state.alerts = changes.alerts || [];
    dom.total.textContent = dataset.events.length;
    const valpoCount = dataset.events.filter((event) => event.location?.city === "Valparaíso").length;
    const vinaCount = dataset.events.filter((event) => event.location?.city === "Viña del Mar").length;
    dom.valpoCounts.forEach((node) => { node.textContent = valpoCount; });
    dom.vinaCounts.forEach((node) => { node.textContent = vinaCount; });
    dom.updated.textContent = formatGeneratedAt(dataset.generated_at);
    populateFilters();
    restoreUrlState();
    renderFeatured();
    renderCategoryShortcuts();
    renderTabs();
    renderResults({ writeUrl: false });
    dom.status.hidden = true;
    dom.content.forEach((node) => { node.hidden = false; });
    const requested = new URL(location.href).searchParams.get("evento");
    const event = findEventById(dataset.events, requested);
    if (event) openDetail(event, document.body);
  } catch (error) {
    dom.status.hidden = true;
    dom.error.hidden = false;
    dom.error.textContent = `No fue posible cargar la agenda: ${error.message}`;
    document.querySelector("#explorar").hidden = false;
  }
}

function applyHeaderQuery(value, { scroll = false } = {}) {
  dom.query.value = value;
  state.section = "proximos";
  renderTabs();
  renderResults();
  if (scroll) document.querySelector("#explorar")?.scrollIntoView({ block: "start" });
}

function showCompleteAgenda() {
  state.section = "proximos";
  renderTabs();
  renderResults();
  document.querySelector("#explorar")?.scrollIntoView({ block: "start" });
}

dom.form?.addEventListener("submit", (event) => event.preventDefault());
dom.form?.addEventListener("input", () => renderResults());
dom.form?.addEventListener("change", () => renderResults());
dom.clear?.addEventListener("click", clearFilters);
dom.emptyClear?.addEventListener("click", clearFilters);
dom.shortcuts.forEach((button) => button.addEventListener("click", () => {
  dom.city.value = button.dataset.cityShortcut;
  renderResults();
  document.querySelector("#explorar")?.scrollIntoView({ block: "start" });
}));
dom.close?.addEventListener("click", closeDetail);
dom.back?.addEventListener("click", closeDetail);
dom.dialog?.addEventListener("click", (event) => { if (event.target === dom.dialog) closeDetail(); });
dom.dialog?.addEventListener("close", afterDetailClose);
dom.headerQuery?.addEventListener("input", (event) => applyHeaderQuery(event.target.value));
dom.headerQuery?.addEventListener("search", (event) => applyHeaderQuery(event.target.value, { scroll: true }));
dom.mobileQuery?.addEventListener("input", (event) => applyHeaderQuery(event.target.value));
dom.mobileQuery?.addEventListener("search", (event) => applyHeaderQuery(event.target.value, { scroll: true }));
dom.mobileSearchToggle?.addEventListener("click", () => {
  const willOpen = dom.mobileSearchRow.hidden;
  dom.mobileSearchRow.hidden = !willOpen;
  dom.mobileSearchToggle.setAttribute("aria-expanded", String(willOpen));
  if (willOpen) requestAnimationFrame(() => dom.mobileQuery?.focus());
});
dom.topCity?.addEventListener("change", () => {
  dom.city.value = dom.topCity.value;
  renderResults();
  document.querySelector("#explorar")?.scrollIntoView({ block: "start" });
});
dom.topCategory?.addEventListener("change", () => {
  state.section = "proximos";
  dom.category.value = dom.topCategory.value;
  renderTabs();
  renderResults();
  document.querySelector("#explorar")?.scrollIntoView({ block: "start" });
});
dom.topSections.forEach((button) => button.addEventListener("click", () => {
  state.section = button.dataset.topSection;
  renderTabs();
  renderResults();
  document.querySelector("#explorar")?.scrollIntoView({ block: "start" });
}));
dom.showAll?.addEventListener("click", showCompleteAgenda);
dom.categoryAll?.addEventListener("click", () => {
  state.section = "proximos";
  dom.category.value = "";
  renderTabs();
  renderResults();
  document.querySelector("#categorias")?.scrollIntoView({ block: "center" });
});

initialize();
